app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100 }));
```

### 2. Global Error Handler (Missing)

The app has no error handling middleware. Unhandled errors will crash the process or leak stack traces:

```js
// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// Central error handler (MUST have 4 args)
app.use((err, req, res, next) => {
  console.error(err);  // log internally
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message,
  });
});
```

### 3. Input Validation (Missing)

`/users` takes no input today, but once you add query params or a `/users/:id` route, validate aggressively. Example with `zod` or `express-validator`:

```js
const { z } = require('zod');

const idSchema = z.coerce.number().int().positive();

app.get('/users/:id', (req, res, next) => {
  try {
    const id = idSchema.parse(req.params.id);
    // ... lookup
  } catch (err) {
    return res.status(400).json({ error: 'Invalid user id' });
  }
});
```

Key rules:
- **Whitelist, don't blacklist** — define exactly what you accept.
- **Coerce then validate** — never trust `typeof` from query strings.
- **Cap string lengths** to prevent ReDoS and memory abuse.

### 4. Async Error Safety

