app.use((err, req, res, _next) => {
  // Log full error server-side, return a safe message to the client
  console.error({ msg: err.message, stack: err.stack, path: req.path });
  const status = err.status || 500;
  res.status(status).json({ error: status === 500 ? 'Internal error' : err.message });
});

process.on('unhandledRejection', (e) => console.error('unhandledRejection', e));
process.on('uncaughtException',  (e) => { console.error('uncaughtException', e); process.exit(1); });
```

## 3. No input validation on routes

**Issue:** `/users` currently takes no input, but as soon as filters/pagination/lookup-by-id are added, unvalidated query/body/param inputs are the #1 source of injection and abuse bugs.

