  console.error({ msg: 'unhandled_rejection', reason });
});
process.on('uncaughtException', (err) => {
  console.error({ msg: 'uncaught_exception', err: err.message });
  process.exit(1); // fail fast; let the orchestrator restart
});
```

---

## 2. No Security Middleware

**Issue:** Missing headers (`X-Frame-Options`, `Content-Security-Policy`, etc.), no rate limiting, no body-size limits.

**Suggestion:**
```js
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

app.disable('x-powered-by');                       // don't advertise Express
app.use(helmet());                                 // secure headers
app.use(express.json({ limit: '10kb' }));          // cap body size (DoS prevention)
app.use(rateLimit({ windowMs: 60_000, max: 100 })); // basic abuse throttle
```

---

## 3. Input Validation (Preventive)

**Issue:** Once `/users` accepts query params or path params (e.g. `/users/:id`), raw input flows through. Never trust `req.query`, `req.params`, or `req.body`.

**Suggestion:** Use a schema validator like `zod` or `joi`:
```js
const { z } = require('zod');

const userIdSchema = z.coerce.number().int().positive().max(1_000_000);

app.get('/users/:id', (req, res, next) => {
  const parsed = userIdSchema.safeParse(req.params.id);
  if (!parsed.success) {
    return res.status(400).json({ error: 'Invalid user id' });
  }
  // use parsed.data — never req.params.id directly
  // ... fetch user
});
```
