const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const morgan = require('morgan');
const { z } = require('zod');

const app = express();

// Security headers
app.use(helmet());

// Request logging
app.use(morgan('combined'));

// Body parsing with size cap
app.use(express.json({ limit: '10kb' }));

// Rate limiting
app.use(rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// Env validation
const EnvSchema = z.object({
  PORT: z.coerce.number().int().positive().default(3000),
  NODE_ENV: z.enum(['development', 'test', 'production']).default('development'),
});
const env = EnvSchema.parse(process.env);

app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', requireAuth, (_req, res) => {
  // TODO: move to a data layer; do not hardcode PII
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

// Example validated route
const IdParam = z.object({ id: z.coerce.number().int().positive() });
app.get('/users/:id', requireAuth, (req, res, next) => {
  const parsed = IdParam.safeParse(req.params);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid id' });
  // ...lookup
});

// 404
app.use((_req, res) => res.status(404).json({ error: 'Not found' }));

// Global error handler — never leak stack traces
app.use((err, _req, res, _next) => {
  console.error({ msg: 'request_error', err: err.message, stack: err.stack });
  const status = err.status || 500;
  res.status(status).json({
    error: status >= 500 ? 'Internal server error' : err.message,
  });
});

const server = app.listen(env.PORT, () => {
  console.log(`Server running on port ${env.PORT}`);
});

server.on('error', (err) => {
  console.error('Server failed to start:', err);
  process.exit(1);
});

// Graceful shutdown
for (const sig of ['SIGTERM', 'SIGINT']) {
  process.on(sig, () => {
    console.log(`${sig} received, shutting down`);
    server.close(() => process.exit(0));
    setTimeout(() => process.exit(1), 10_000).unref();
  });
}

// Last-resort handlers
process.on('unhandledRejection', (reason) => {
  console.error('unhandledRejection', reason);
});
process.on('uncaughtException', (err) => {
  console.error('uncaughtException', err);
  process.exit(1);
});

function requireAuth(req, res, next) {
  // Replace with real auth (JWT, session, etc.)
  if (!req.headers.authorization) return res.status(401).json({ error: 'Unauthorized' });
  next();
}

module.exports = app;
```

---

## Priority order for a real fix

1. **Global error handler + 404 handler** — prevents stack-trace leaks.
2. **`helmet` + rate limiting** — cheap defense in depth.
3. **Env/config validation** — stop hardcoded secrets/ports.
4. **Auth on `/users`** — PII shouldn't be public.
5. **Input validation library** — before you add any route that takes user input.
6. **Graceful shutdown + startup error handling** — operational reliability.
7. **Structured logging** — required for debugging in production.

