app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// Centralized error handler — must have 4 args
app.use((err, req, res, next) => {
  console.error(err); // consider a structured logger (pino/winston)
  // Do NOT leak err.message or stack to clients in production
  res.status(err.status || 500).json({ error: 'Internal Server Error' });
});

process.on('unhandledRejection', (reason) => {
  console.error('Unhandled rejection:', reason);
});
process.on('uncaughtException', (err) => {
  console.error('Uncaught exception:', err);
  process.exit(1); // fail fast; let a supervisor restart
});
```

## 2. `app.listen` has no error callback

If the port is in use or binding fails, the failure is silent-ish. Capture the server handle and listen for `error`:

```js
const server = app.listen(PORT, () => { ... });
server.on('error', (err) => {
  console.error('Failed to start server:', err);
  process.exit(1);
});
```

## 3. No input validation on routes

Neither route currently takes input, but as soon as you add `req.query`, `req.params`, or `req.body`, validate explicitly. Use a schema library (`zod`, `joi`, `express-validator`) rather than hand-rolled checks:

```js
const { z } = require('zod');

const UserIdSchema = z.object({ id: z.coerce.number().int().positive() });

