// Security headers
app.use(helmet());
app.disable('x-powered-by');

// Body parsing with size cap (mitigates payload DoS)
app.use(express.json({ limit: '10kb' }));

// Structured logging
app.use(morgan('combined'));

// Rate limiting
app.use(rateLimit({
  windowMs: 60_000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// Routes
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res, next) => {
  try {
    // TODO: require auth; do not expose PII to unauthenticated clients
    res.json([
      { id: 1, name: 'Alice' },
      { id: 2, name: 'Bob' },
    ]);
  } catch (err) {
    next(err);
  }
});

// 404
app.use((req, res) => res.status(404).json({ error: 'Not Found' }));

// Centralized error handler — never leak stack traces
app.use((err, req, res, _next) => {
  console.error({ msg: 'unhandled_error', err: err.message, stack: err.stack });
  res.status(err.status || 500).json({ error: 'Internal Server Error' });
});

module.exports = app;
```

And split the bootstrap into a separate `server.js`:

```js
const app = require('./app');

const port = Number(process.env.PORT) || 3000;
if (!Number.isInteger(port) || port < 1 || port > 65535) {
  throw new Error(`Invalid PORT: ${process.env.PORT}`);
}

const server = app.listen(port, () => console.log(`Listening on ${port}`));

for (const sig of ['SIGTERM', 'SIGINT']) {
  process.on(sig, () => server.close(() => process.exit(0)));
}
process.on('unhandledRejection', (reason) => {
  console.error({ msg: 'unhandled_rejection', reason });
});
```

