const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
const PORT = process.env.PORT || 3000;
const isProd = process.env.NODE_ENV === 'production';

// Security headers (CSP, HSTS, no-sniff, frame-deny, etc.)
app.use(helmet());
app.disable('x-powered-by');

// Parse JSON with a strict size cap to prevent DoS
app.use(express.json({ limit: '10kb' }));

// Basic rate limit — tune per-route as needed
app.use(rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// Async wrapper so thrown errors reach the error middleware
const asyncHandler = (fn) => (req, res, next) =>
  Promise.resolve(fn(req, res, next)).catch(next);

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', asyncHandler(async (req, res) => {
  // TODO: require authentication before returning user data
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]); // email removed — don't return PII to unauthenticated callers
}));

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// Error-handling middleware — must have 4 args
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  console.error({ msg: 'unhandled error', err: err.stack, path: req.path });
  res.status(err.status || 500).json({
    error: isProd ? 'Internal server error' : err.message,
  });
});

const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// Graceful shutdown
for (const sig of ['SIGTERM', 'SIGINT']) {
  process.on(sig, () => {
    console.log(`${sig} received, shutting down`);
    server.close(() => process.exit(0));
    setTimeout(() => process.exit(1), 10_000).unref(); // hard kill after 10s
  });
}

module.exports = app;
```

---

## Additional Recommendations (for when routes grow)

- **Input validation library**: Use `zod`, `joi`, or `express-validator` for any route that accepts params, query strings, or bodies. Validate *types, ranges, and shapes* — never trust `req.body.foo` directly.
- **Parameterized queries**: When `/users` talks to a real DB, use parameterized/prepared statements (e.g., `pg` with `$1` placeholders, or an ORM). Never interpolate `req.params.id` into SQL.
- **Authn / Authz**: Add middleware (JWT, session, etc.) in front of anything returning user data. The `/users` endpoint as written would be a GDPR problem in production.
- **CORS**: Add `cors` middleware with an explicit allowlist rather than the default `*`.
- **Secrets via env**: Use `dotenv` in dev and a secret manager in prod. Never commit `.env`.
- **Dependency hygiene**: Run `npm audit` in CI and pin versions with a lockfile.
- **Logging**: Replace `console.*` with structured logging (`pino` or `winston`) and scrub PII before logging request bodies.
- **`process.on('unhandledRejection' | 'uncaughtException')`**: Log and exit — let the orchestrator restart the process rather than limping along in an unknown state.

