  // Log full error server-side, send opaque message client-side
  console.error({ msg: 'unhandled', err: err.stack });
  res.status(500).json({ error: 'Internal server error' });
});

// --- Process-level safety nets ---
process.on('unhandledRejection', (reason) => {
  console.error({ msg: 'unhandledRejection', reason });
});
process.on('uncaughtException', (err) => {
  console.error({ msg: 'uncaughtException', err: err.stack });
  process.exit(1); // Fail fast; let supervisor restart
});

// --- Start only when executed directly ---
const PORT = Number(process.env.PORT) || 3000;
if (!Number.isInteger(PORT) || PORT < 1 || PORT > 65535) {
  throw new Error(`Invalid PORT: ${process.env.PORT}`);
}
